/// <reference path="../pb_data/types.d.ts" />

cronAdd("archive_old_messages", "0 0 * * *", function () {
    // Calculate the threshold date: 30 days ago from now
    var threshold = new Date();
    threshold.setDate(threshold.getDate() - 30);

    // Format the date as a PocketBase-compatible datetime string: YYYY-MM-DD HH:mm:ss.SSS
    var pad = function (n, len) {
        return String(n).padStart(len || 2, "0");
    };

    var thresholdStr =
        threshold.getUTCFullYear() +
        "-" +
        pad(threshold.getUTCMonth() + 1) +
        "-" +
        pad(threshold.getUTCDate()) +
        " " +
        pad(threshold.getUTCHours()) +
        ":" +
        pad(threshold.getUTCMinutes()) +
        ":" +
        pad(threshold.getUTCSeconds()) +
        "." +
        pad(threshold.getUTCMilliseconds(), 3);

    // Query records older than 30 days that have not been archived yet
    var filter = "created < '" + thresholdStr + "' && archived = false";
    var records = $app.dao().findRecordsByFilter("messages", filter, "", 0, 0);

    // Archive each matched record
    for (var i = 0; i < records.length; i++) {
        var record = records[i];
        record.set("archived", true);
        $app.dao().saveRecord(record);
    }
});

